UPDATE announcement_post SET translations = '{"de":{"title":"Neue Snapchat-Daten jetzt verfügbar!","content":[{"type":"announcement-title","children":[{"text":"Neue Snapchat-Daten jetzt verfügbar!"}]},{"type":"paragraph","children":[{"bold":true,"text":"Sie können jetzt Snapchat-Daten für Künstler verfolgen!"}]},{"type":"paragraph","children":[{"text":"Tauchen Sie tiefer in die Social-Media-Präsenz Ihrer Künstler ein mit umfassenden Snapchat-Daten, die jetzt in Chartmetric integriert sind."}]},{"type":"paragraph","children":[{"text":"Verfolgen Sie das Follower-Wachstum und analysieren Sie Zielgruppen-Demographics direkt von Ihren Künstlerprofilen und Listen aus, um ein vollständiges Bild der Social-Media-Performance auf einer weiteren wichtigen Plattform zu erhalten, auf der Musikentdeckung stattfindet."}]},{"type":"paragraph","children":[{"text":"Bereit zum Erkunden? Schauen Sie sich noch heute die Snapchat-Daten für Ihre Künstler an!"}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/58e6f9f8-fbdc-4846-8954-0fe40a56d94e.png","type":"image","children":[{"text":""}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/f5c9baf7-7b8c-45ec-b008-3a0cf6083a17.png","type":"image","children":[{"text":""}]}]},"es":{"title":"¡Nuevos datos de Snapchat ya disponibles!","content":[{"type":"announcement-title","children":[{"text":"¡Datos de Snapchat ya disponibles!"}]},{"type":"paragraph","children":[{"bold":true,"text":"¡Ahora puedes rastrear datos de Snapchat para artistas!"}]},{"type":"paragraph","children":[{"text":"Profundiza en la presencia social de tu artista con datos completos de Snapchat ahora integrados en Chartmetric."}]},{"type":"paragraph","children":[{"text":"Rastrea el crecimiento de seguidores y analiza la demografía de la audiencia directamente desde los perfiles y listas de tus artistas, brindándote una imagen completa del rendimiento en redes sociales en otra plataforma clave donde ocurre el descubrimiento musical."}]},{"type":"paragraph","children":[{"text":"¿Listo para explorar? ¡Revisa los datos de Snapchat para tu artista hoy!"}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/58e6f9f8-fbdc-4846-8954-0fe40a56d94e.png","type":"image","children":[{"text":""}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/f5c9baf7-7b8c-45ec-b008-3a0cf6083a17.png","type":"image","children":[{"text":""}]}]},"fr":{"title":"Nouvelles données Snapchat maintenant disponibles !","content":[{"type":"announcement-title","children":[{"text":"Nouvelles données Snapchat maintenant disponibles !"}]},{"type":"paragraph","children":[{"bold":true,"text":"Vous pouvez maintenant suivre les données Snapchat des artistes !"}]},{"type":"paragraph","children":[{"text":"Plongez plus profondément dans la présence sociale de votre artiste avec des données Snapchat complètes maintenant intégrées dans Chartmetric."}]},{"type":"paragraph","children":[{"text":"Suivez la croissance des abonnés et analysez les données démographiques de l''audience directement depuis vos profils d''artistes et listes, vous donnant une vue d''ensemble complète des performances sur les réseaux sociaux sur une autre plateforme clé où la découverte musicale se produit."}]},{"type":"paragraph","children":[{"text":"Prêt à explorer ? Consultez les données Snapchat de votre artiste dès aujourd''hui !"}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/58e6f9f8-fbdc-4846-8954-0fe40a56d94e.png","type":"image","children":[{"text":""}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/f5c9baf7-7b8c-45ec-b008-3a0cf6083a17.png","type":"image","children":[{"text":""}]}]},"ja":{"title":"新しいSnapchatデータが利用可能になりました！","content":[{"type":"announcement-title","children":[{"text":"新しいSnapchatデータが利用可能になりました！"}]},{"type":"paragraph","children":[{"bold":true,"text":"アーティストのSnapchatデータを追跡できるようになりました！"}]},{"type":"paragraph","children":[{"text":"ChartmetricにSnapchatの包括的なデータが統合され、アーティストのソーシャルメディアでの存在感をより深く分析できます。"}]},{"type":"paragraph","children":[{"text":"フォロワーの成長を追跡し、アーティストプロフィールやリストから直接オーディエンスの人口統計を分析することで、音楽発見が行われる重要なプラットフォームにおけるソーシャルメディアパフォーマンスの全体像を把握できます。"}]},{"type":"paragraph","children":[{"text":"探索の準備はできましたか？今すぐあなたのアーティストのSnapchatデータをチェックしてください！"}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/58e6f9f8-fbdc-4846-8954-0fe40a56d94e.png","type":"image","children":[{"text":""}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/f5c9baf7-7b8c-45ec-b008-3a0cf6083a17.png","type":"image","children":[{"text":""}]}]},"ko":{"title":"새로운 Snapchat 데이터를 이제 이용할 수 있습니다!","content":[{"type":"announcement-title","children":[{"text":"새로운 Snapchat 데이터를 이용할 수 있습니다!"}]},{"type":"paragraph","children":[{"bold":true,"text":"이제 아티스트의 Snapchat 데이터를 추적할 수 있습니다!"}]},{"type":"paragraph","children":[{"text":"Chartmetric에 통합된 포괄적인 Snapchat 데이터로 아티스트의 소셜 미디어 존재감을 더 깊이 파악해보세요."}]},{"type":"paragraph","children":[{"text":"팔로워 증가를 추적하고 아티스트 프로필 및 목록에서 직접 오디언스 인구통계를 분석하여, 음악 발견이 일어나는 또 다른 핵심 플랫폼에서의 소셜 미디어 성과에 대한 완전한 그림을 얻을 수 있습니다."}]},{"type":"paragraph","children":[{"text":"탐색할 준비가 되셨나요? 오늘 바로 아티스트의 Snapchat 데이터를 확인해보세요!"}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/58e6f9f8-fbdc-4846-8954-0fe40a56d94e.png","type":"image","children":[{"text":""}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/f5c9baf7-7b8c-45ec-b008-3a0cf6083a17.png","type":"image","children":[{"text":""}]}]},"pt":{"title":"Novos Dados do Snapchat Já Disponíveis!","content":[{"type":"announcement-title","children":[{"text":"Novos Dados do Snapchat Já Disponíveis!"}]},{"type":"paragraph","children":[{"bold":true,"text":"Agora você pode acompanhar dados do Snapchat para artistas!"}]},{"type":"paragraph","children":[{"text":"Mergulhe mais fundo na presença social do seu artista com dados abrangentes do Snapchat agora integrados ao Chartmetric."}]},{"type":"paragraph","children":[{"text":"Acompanhe o crescimento de seguidores e analise dados demográficos da audiência diretamente dos perfis e listas de seus artistas, oferecendo uma visão completa do desempenho nas redes sociais em mais uma plataforma-chave onde a descoberta musical acontece."}]},{"type":"paragraph","children":[{"text":"Pronto para explorar? Confira os dados do Snapchat para seu artista hoje mesmo!"}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/58e6f9f8-fbdc-4846-8954-0fe40a56d94e.png","type":"image","children":[{"text":""}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/f5c9baf7-7b8c-45ec-b008-3a0cf6083a17.png","type":"image","children":[{"text":""}]}]}}'::jsonb WHERE id = 5;

