UPDATE announcement_post SET translations = '{"de":{"title":"Einführung neuer Smart Filter für die Künstlerliste","content":[{"type":"announcement-title","children":[{"text":"Einführung der neuen Smart Filter in der Artist List"}]},{"type":"paragraph","children":[{"text":"Unsere neuen Smart Filter machen das Finden von Künstlern schneller und einfacher denn je, mit einem verbesserten Design, das endloses Klicken reduziert."}]},{"type":"paragraph","children":[{"text":"Jetzt können Sie:"}]},{"type":"bulleted-list","children":[{"type":"list-item","children":[{"text":"Mit weniger Klicks filtern — optimierte Bedienelemente bringen die Kontrolle an Ihre Fingerspitzen"}]}]},{"type":"bulleted-list","children":[{"type":"list-item","children":[{"text":"Künstler schneller finden — intuitives Design hilft Ihnen, sich auf die wichtigen Statistiken zu konzentrieren"}]}]},{"type":"bulleted-list","children":[{"type":"list-item","children":[{"text":"Effizienter arbeiten — weniger Zeit mit Suchen verbringen, mehr Zeit mit Strategieentwicklung"}]}]},{"type":"paragraph","children":[{"text":"Gehen Sie zur "},{"url":"https://app.chartmetric.com/artists","type":"link","children":[{"text":"Artist List"}]},{"text":" und erleben Sie das Upgrade selbst!"}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/b71ee0cd-a359-452d-8511-36bb53ff727a.png","type":"image","children":[{"text":""}]}]},"es":{"title":"Presentamos los Nuevos Filtros Inteligentes en la Lista de Artistas","content":[{"type":"announcement-title","children":[{"text":"Presentamos los Nuevos Filtros Inteligentes en la Lista de Artistas"}]},{"type":"paragraph","children":[{"text":"Nuestros nuevos Filtros Inteligentes hacen que encontrar artistas sea más rápido y fácil que nunca, con un diseño mejorado que reduce los clics interminables."}]},{"type":"paragraph","children":[{"text":"Ahora puedes:"}]},{"type":"bulleted-list","children":[{"type":"list-item","children":[{"text":"Filtrar con menos clics — contr