UPDATE announcement_post SET translations = '{"de":{"title":"Künstlerprofile haben gerade ein großes Glow-Up erhalten!","content":[{"type":"announcement-title","children":[{"text":"Künstlerprofile haben ein großartiges Makeover erhalten!"}]},{"type":"paragraph","children":[{"bold":true,"text":"Ihre Lieblingskünstler haben jetzt atemberaubende neue Profilbanner, die so einzigartig sind wie ihre Musik!"}]},{"type":"paragraph","children":[{"text":"Künstler-, Track- und Playlist-Seiten verfügen nun alle über einen "},{"bold":true,"text":"wunderschön gestalteten Header "},{"text":"mit ihren eigenen Bildern als Hintergrund, was für ein einzigartigeres und intensiveres Erlebnis sorgt."}]},{"type":"paragraph","children":[{"text":"Außerdem haben wir es einfacher denn je gemacht, auf "},{"bold":true,"text":"Onesheet "},{"text":"direkt von Künstlerprofilen zuzugreifen, sodass Sie schnell eine dynamische Präsentation für Ihren Künstler direkt von der Seite aus erstellen können."}]},{"type":"paragraph","children":[{"text":"Schauen Sie sich noch heute die aufgefrischten Künstlerprofile an und sehen Sie den Unterschied selbst."}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/94441179-16fa-4a34-b58e-0377c9ca1276.png","type":"image","children":[{"text":""}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/1191743e-4adc-4636-be42-0ab79e3322aa.png","type":"image","children":[{"text":""}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/c7af730d-2fa6-40eb-91e4-0bbdb7bb374d.png","type":"image","children":[{"text":""}]}]},"es":{"title":"¡Los Perfiles de Artistas Acaban de Recibir una Renovación Increíble!","content":[{"type":"announcement-title","children":[{"text":"¡Los Perfiles de Artistas Acaban de Recibir una Renovación Increíble!"}]},{"type":"paragraph","children":[{"bold":true,"text":"¡Tus artistas favoritos ahora tienen impresionantes nuevos banners de perfil que son tan únicos como su música!"}]},{"type":"paragraph","children":[{"text":"Las páginas de artistas, canciones y playlists ahora cuentan con un "},{"bold":true,"text":"encabezado bellamente diseñado "},{"text":"que usa sus propias imágenes como fondo, creando una experiencia más única e inmersiva."}]},{"type":"paragraph","children":[{"text":"Además, hemos facilitado más que nunca el acceso a "},{"bold":true,"text":"Onesheet "},{"text":"directamente desde los perfiles de artistas, para que puedas crear rápidamente una vitrina dinámica para tu artista desde la misma página."}]},{"type":"paragraph","children":[{"text":"Echa un vistazo a los perfiles de artistas renovados hoy y comprueba la diferencia por ti mismo."}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/94441179-16fa-4a34-b58e-0377c9ca1276.png","type":"image","children":[{"text":""}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/1191743e-4adc-4636-be42-0ab79e3322aa.png","type":"image","children":[{"text":""}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/c7af730d-2fa6-40eb-91e4-0bbdb7bb374d.png","type":"image","children":[{"text":""}]}]},"fr":{"title":"Les Profils d''Artistes Viennent de Recevoir une Transformation Majeure !","content":[{"type":"announcement-title","children":[{"text":"Les Profils d''Artistes Viennent de Subir une Transformation Majeure !"}]},{"type":"paragraph","children":[{"bold":true,"text":"Vos artistes préférés ont maintenant de superbes nouvelles bannières de profil aussi uniques que leur musique !"}]},{"type":"paragraph","children":[{"text":"Les pages d''artistes, de morceaux et de playlists présentent toutes désormais un "},{"bold":true,"text":"en-tête magnifiquement conçu "},{"text":"utilisant leurs propres visuels en arrière-plan, créant une expérience plus unique et immersive."}]},{"type":"paragraph","children":[{"text":"De plus, nous avons rendu plus facile que jamais l''accès à "},{"bold":true,"text":"Onesheet "},{"text":"directement depuis les profils d''artistes, vous permettant de créer rapidement une vitrine dynamique pour votre artiste directement depuis la page."}]},{"type":"paragraph","children":[{"text":"Découvrez les profils d''artistes actualisés dès aujourd''hui et voyez la différence par vous-même."}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/94441179-16fa-4a34-b58e-0377c9ca1276.png","type":"image","children":[{"text":""}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/1191743e-4adc-4636-be42-0ab79e3322aa.png","type":"image","children":[{"text":""}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/c7af730d-2fa6-40eb-91e4-0bbdb7bb374d.png","type":"image","children":[{"text":""}]}]},"ja":{"title":"アーティストプロフィールが大幅にパワーアップしました！","content":[{"type":"announcement-title","children":[{"text":"アーティストプロフィールが大幅にパワーアップしました！"}]},{"type":"paragraph","children":[{"bold":true,"text":"お気に入りのアーティストに、彼らの音楽と同じくらいユニークで美しい新しいプロフィールバナーが追加されました！"}]},{"type":"paragraph","children":[{"text":"アーティスト、楽曲、プレイリストのページすべてに"},{"bold":true,"text":"美しくデザインされたヘッダー"},{"text":"が追加され、独自の画像を背景として使用することで、より個性的で没入感のある体験を提供します。"}]},{"type":"paragraph","children":[{"text":"さらに、アーティストプロフィールから直接 "},{"bold":true,"text":"Onesheet"},{"text":"にアクセスしやすくなり、そのページからすぐにアーティストのダイナミックなショーケースを作成できます。"}]},{"type":"paragraph","children":[{"text":"リニューアルされたアーティストプロフィールを今すぐチェックして、その違いをご自身でお確かめください。"}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/94441179-16fa-4a34-b58e-0377c9ca1276.png","type":"image","children":[{"text":""}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/1191743e-4adc-4636-be42-0ab79e3322aa.png","type":"image","children":[{"text":""}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/c7af730d-2fa6-40eb-91e4-0bbdb7bb374d.png","type":"image","children":[{"text":""}]}]},"ko":{"title":"아티스트 프로필이 대대적으로 업그레이드되었습니다!","content":[{"type":"announcement-title","children":[{"text":"아티스트 프로필이 대대적으로 업그레이드되었습니다!"}]},{"type":"paragraph","children":[{"bold":true,"text":"여러분이 좋아하는 아티스트들이 이제 그들의 음악만큼이나 독특한 멋진 새 프로필 배너를 갖게 되었습니다!"}]},{"type":"paragraph","children":[{"text":"아티스트, 트랙, 플레이리스트 페이지 모두 이제 "},{"bold":true,"text":"아름답게 디자인된 헤더"},{"text":"를 제공하며, 아티스트 고유의 이미지를 배경으로 사용하여 더욱 독특하고 몰입감 있는 경험을 선사합니다."}]},{"type":"paragraph","children":[{"text":"또한, 아티스트 프로필에서 바로 "},{"bold":true,"text":"Onesheet"},{"text":"에 접근할 수 있도록 더욱 편리하게 개선하여, 해당 페이지에서 바로 아티스트를 위한 역동적인 쇼케이스를 빠르게 만들 수 있습니다."}]},{"type":"paragraph","children":[{"text":"새롭게 단장된 아티스트 프로필을 오늘 확인해보시고 그 차이를 직접 경험해보세요."}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/94441179-16fa-4a34-b58e-0377c9ca1276.png","type":"image","children":[{"text":""}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/1191743e-4adc-4636-be42-0ab79e3322aa.png","type":"image","children":[{"text":""}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/c7af730d-2fa6-40eb-91e4-0bbdb7bb374d.png","type":"image","children":[{"text":""}]}]},"pt":{"title":"Perfis de Artistas Acabaram de Receber uma Grande Reformulação!","content":[{"type":"announcement-title","children":[{"text":"Os Perfis de Artistas Acabaram de Receber uma Grande Renovação!"}]},{"type":"paragraph","children":[{"bold":true,"text":"Seus artistas favoritos agora têm novos banners de perfil impressionantes que são tão únicos quanto sua música!"}]},{"type":"paragraph","children":[{"text":"As páginas de artistas, faixas e playlists agora apresentam um "},{"bold":true,"text":"cabeçalho lindamente projetado "},{"text":"usando suas próprias imagens como plano de fundo, criando uma experiência mais única e imersiva."}]},{"type":"paragraph","children":[{"text":"Além disso, facilitamos mais do que nunca o acesso ao "},{"bold":true,"text":"Onesheet "},{"text":"diretamente dos perfis de artistas, para que você possa criar rapidamente uma vitrine dinâmica para seu artista direto da página."}]},{"type":"paragraph","children":[{"text":"Confira os perfis de artistas renovados hoje e veja a diferença por si mesmo."}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/94441179-16fa-4a34-b58e-0377c9ca1276.png","type":"image","children":[{"text":""}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/1191743e-4adc-4636-be42-0ab79e3322aa.png","type":"image","children":[{"text":""}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/c7af730d-2fa6-40eb-91e4-0bbdb7bb374d.png","type":"image","children":[{"text":""}]}]}}'::jsonb WHERE id = 9;

UPDATE announcement_post SET translations = '{"de":{"title":"Überwachen Sie Künstler-Statistiken unterwegs mit mobilen Widgets!","content":[{"type":"announcement-title","children":[{"text":"Überwachen Sie die Statistiken Ihrer Künstler unterwegs mit Mobile Widgets!"}]},{"type":"paragraph","children":[{"text":"Mit den Chartmetric Mobile Widgets sind die wichtigsten Statistiken Ihrer Künstler nur einen Blick entfernt auf Ihrem Startbildschirm."}]},{"type":"paragraph","children":[{"text":"Sie können sofort über die neuesten Statistiken und Änderungen der Künstler auf dem Laufenden bleiben."}]},{"type":"paragraph","children":[{"text":"Außerdem haben Sie die Kontrolle: passen Sie an, welche Künstler und Metriken Sie verfolgen möchten, und wählen Sie aus verschiedenen Widget-Ansichten und -Größen, die zu Ihrem Stil passen."}]},{"type":"paragraph","children":[{"text":"Jetzt verfügbar auf "},{"url":"https://apps.apple.com/app/chartmetric/id1522918776","type":"link","children":[{"text":"iOS"}]},{"text":" und "},{"url":"https://play.google.com/store/apps/details?id=com.chartmetric","type":"link","children":[{"text":"Android"}]},{"text":" — laden Sie Ihre Chartmetric App herunter und beginnen Sie noch heute mit der Nutzung von Widgets!"}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/987c1c9c-7a97-44fd-9daf-bc261d27e242.png","type":"image","children":[{"text":""}]}]},"es":{"title":"¡Monitorea las Estadísticas del Artista en Movimiento con Widgets Móviles!","content":[{"type":"announcement-title","children":[{"text":"¡Monitorea las Estadísticas del Artista sobre la Marcha con Widgets Móviles!"}]},{"type":"paragraph","children":[{"text":"Con los Widgets Móviles de Chartmetric, las estadísticas clave de tu artista están a solo un vistazo en tu pantalla de inicio."}]},{"type":"paragraph","children":[{"text":"Puedes mantenerte instantáneamente actualizado con las últimas estadísticas y cambios de los artistas."}]},{"type":"paragraph","children":[{"tex