-2.amazonaws.com/2958395/987c1c9c-7a97-44fd-9daf-bc261d27e242.png","type":"image","children":[{"text":""}]}]},"ja":{"title":"モバイルウィジェットでアーティストの統計情報を外出先でも監視！","content":[{"type":"announcement-title","children":[{"text":"Mobile Widgetでアーティストの統計をいつでもモニタリング！"}]},{"type":"paragraph","children":[{"text":"Chartmetric Mobile Widgetを使えば、ホーム画面で一目でアーティストの主要統計を確認できます。"}]},{"type":"paragraph","children":[{"text":"アーティストの最新統計や変化を瞬時に把握できます。"}]},{"type":"paragraph","children":[{"text":"さらに、あなたが主導権を握れます：追跡したいアーティストと指標をカスタマイズし、複数のウィジェット表示とサイズからあなたのスタイルに合ったものを選択できます。"}]},{"type":"paragraph","children":[{"text":"現在利用可能： "},{"url":"https://apps.apple.com/app/chartmetric/id1522918776","type":"link","children":[{"text":"iOS"}]},{"text":" および "},{"url":"https://play.google.com/store/apps/details?id=com.chartmetric","type":"link","children":[{"text":"Android"}]},{"text":" — Chartmetricアプリをダウンロードして、今すぐウィジェットを使い始めましょう！"}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/987c1c9c-7a97-44fd-9daf-bc261d27e242.png","type":"image","children":[{"text":""}]}]},"ko":{"title":"모바일 위젯으로 이동 중에도 아티스트 통계를 모니터링하세요!","content":[{"type":"announcement-title","children":[{"text":"Mobile Widget으로 이동 중에도 아티스트 통계를 모니터링하세요!"}]},{"type":"paragraph","children":[{"text":"Chartmetric Mobile Widget을 사용하면 홈 화면에서 한눈에 아티스트의 핵심 통계를 확인할 수 있습니다."}]},{"type":"paragraph","children":[{"text":"아티스트의 최신 통계와 변화를 즉시 업데이트받을 수 있습니다."}]},{"type":"paragraph","children":[{"text":"또한 완전한 제어가 가능합니다: 추적하고 싶은 아티스트와 지표를 사용자 정의하고, 여러 위젯 뷰와 크기 중에서 자신의 스타일에 맞는 것을 선택하세요."}]},{"type":"paragraph","children":[{"text":"지금 이용 가능: "},{"url":"https://apps.apple.com/app/chartmetric/id1522918776","type":"link","children":[{"text":"iOS"}]},{"text":" 및 "},{"url":"https://play.google.com/store/apps/details?id=com.chartmetric","type":"link","children":[{"text":"Android"}]},{"text":" — Chartmetric 앱을 다운로드하고 오늘부터 위젯을 사용해보세요!"}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/987c1c9c-7a97-44fd-9daf-bc261d27e242.png","type":"image","children":[{"text":""}]}]},"pt":{"title":"Monitore as Estatísticas do Artista em Movimento com Widgets Mobile!","content":[{"type":"announcement-title","children":[{"text":"Monitore as Estatísticas do Artista em Movimento com Widgets Mobile!"}]},{"type":"paragraph","children":[{"text":"Com os Widgets Mobile do Chartmetric, as principais estatísticas do seu artista estão a apenas um olhar de distância na sua tela inicial."}]},{"type":"paragraph","children":[{"text":"Você pode se manter instantaneamente atualizado com as últimas estatísticas e mudanças dos artistas."}]},{"type":"paragraph","children":[{"text":"Além disso, você tem o controle: personalize quais artistas e métricas você quer acompanhar, e escolha entre múltiplas visualizações e tamanhos de widget para combinar com seu estilo."}]},{"type":"paragraph","children":[{"text":"Agora disponível no "},{"url":"https://apps.apple.com/app/chartmetric/id1522918776","type":"link","children":[{"text":"iOS"}]},{"text":" e "},{"url":"https://play.google.com/store/apps/details?id=com.chartmetric","type":"link","children":[{"text":"Android"}]},{"text":" — baixe seu app Chartmetric e comece a usar widgets hoje!"}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/987c1c9c-7a97-44fd-9daf-bc261d27e242.png","type":"image","children":[{"text":""}]}]}}'::jsonb WHERE id = 10;

UPDATE announcement_post SET translations = '{"de":{"title":"Neuer Tab für nutzergenerierte Inhalte (UGC) auf der Künstlerseite","content":[{"type":"announcement-title","children":[{"text":"Neuer User-Generated Content (UGC) Tab auf der Künstlerseite"}]},{"type":"paragraph","children":[{"text":"Entdecken Sie, wie Fans mit Ihrer Musik interagieren im neuen User Generated Content Tab auf den Künstlerseiten!"}]},{"type":"paragraph","children":[{"text":"Überwachen Sie Kommentar-Sentiment, Engagement-Analytics und sehen Sie, wo Nutzer Videos mit den Tracks Ihrer Künstler posten. Dieses leistungsstarke Tool hilft Ihnen dabei zu identifizieren, welche Plattformen das meiste Engagement generieren und wo Fans am aktivsten Content mit der Musik Ihrer Künstler erstellen."}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/6988f594-4353-4b34-96c5-a30634685f9d.png","type":"image","children":[{"text":""}]}]},"es":{"title":"Nueva pestaña de Contenido Generado por Usuarios (UGC) en la Página del Artista","content":[{"type":"announcement-title","children":[{"text":"Nueva pestaña de Contenido Generado por el Usuario (UGC) en la Página del Artista"}]},{"type":"paragraph","children":[{"text":"¡Descubre cómo los fanáticos están interactuando con tu música en la nueva pestaña de Contenido Generado por el Usuario en las Páginas de Artistas!"}]},{"type":"paragraph","children":[{"text":"Monitorea el sentimiento de los comentarios, analíticas de engagement y observa dónde los usuarios están publicando videos con las canciones de tu artista. Esta poderosa herramienta te ayuda a identificar qué plataformas están generando más engagement y dónde los fanáticos están creando más activamente contenido con la música de tu artista."}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/6988f594-4353-4b34-96c5-a30634685f9d.png","type":"image","children":[{"text":""}]}]},"fr":{"title":"Nouvel onglet Contenu Généré par les Utilisateurs (UGC) sur la Page Artiste","content":[{"type":"announcement-title","children":[{"text":"Nouvel onglet Contenu Généré par les Utilisateurs (UGC) sur la Page Artiste"}]},{"type":"paragraph","children":[{"text":"Découvrez comment les fans interagissent avec votre musique dans le nouvel onglet Contenu Généré par les Utilisateurs sur les Pages Artistes !"}]},{"type":"paragraph","children":[{"text":"Surveillez le sentiment des commentaires, les analyses d''engagement, et voyez où les utilisateurs publient des vidéos avec les morceaux de votre artiste. Cet outil puissant vous aide à identifier quelles plateformes génèrent le plus d''engagement et où les fans créent le plus activement du contenu avec la musique de votre artiste."}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/6988f594-4353-4b34-96c5-a30634685f9d.png","type":"image","children":[{"text":""}]}]},"ja":{"title":"アーティストページの新しいユーザー生成コンテンツ（UGC）タブ","content":[{"type":"announcement-title","children":[{"text":"アーティストページの新しいユーザー生成コンテンツ（UGC）タブ"}]},{"type":"paragraph","children":[{"text":"アーティストページの新しいユーザー生成コンテンツタブで、ファンがあなたの音楽にどのように関わっているかを発見しましょう！"}]},{"type":"paragraph","children":[{"text":"コメントセンチメント、エンゲージメント分析を監視し、ユーザーがあなたのアーティストの楽曲をフィーチャーした動画をどこに投稿しているかを確認できます。この強力なツールは、どのプラットフォームが最もエンゲージメントを促進し、ファンがあなたのアーティストの音楽で最も活発にコンテンツを作成している場所を特定するのに役立ちます。"}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/6988f594-4353-4b34-96c5-a30634685f9d.png","type":"image","children":[{"text":""}]}]},"ko":{"title":"Artist Page의 새로운 사용자 제작 콘텐츠(UGC) 탭","content":[{"type":"announcement-title","children":[{"text":"Artist Page의 새로운 User-Generated Content (UGC) 탭"}]},{"type":"paragraph","children":[{"text":"Artist Pages의 새로운 User Generated Content 탭에서 팬들이 당신의 음악과 어떻게 상호작용하는지 알아보세요!"}]},{"type":"paragraph","children":[{"text":"댓글 감정 분석, 참여도 분석을 모니터링하고 사용자들이 당신의 아티스트 트랙이 포함된 영상을 어디에 게시하는지 확인하세요. 이 강력한 도구는 어떤 플랫폼이 가장 많은 참여를 유도하고 있는지, 그리고 팬들이 당신의 아티스트 음악으로 가장 활발하게 콘텐츠를 제작하는 곳이 어디인지 파악하는 데 도움을 줍니다."}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/6988f594-4353-4b34-96c5-a30634685f9d.png","type":"image","children":[{"text":""}]}]},"pt":{"title":"Nova aba de Conteúdo Gerado pelo Usuário (UGC) na Página do Artista","content":[{"type":"announcement-title","children":[{"text":"Nova aba de Conteúdo Gerado pelo Usuário (UGC) na Página do Artista"}]},{"type":"paragraph","children":[{"text":"Descubra como os fãs estão se envolvendo com sua música na nova aba de Conteúdo Gerado pelo Usuário nas Páginas de Artistas!"}]},{"type":"paragraph","children":[{"text":"Monitore o sentimento dos comentários, análises de engajamento e veja onde os usuários estão postando vídeos com as faixas do seu artista. Esta ferramenta poderosa ajuda você a identificar quais plataformas estão gerando mais engajamento e onde os fãs estão criando conteúdo mais ativamente com a música do seu artista."}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/6988f594-4353-4b34-96c5-a30634685f9d.png","type":"image","children":[{"text":""}]}]}}'::jsonb WHERE id = 11;

UPDATE announcement_post SET translations = '{"de":{"title":"Entdecken Sie Features im neuen Chartmetric Onboarding Center!","content":[{"type":"announcement-title","children":[{"text":"Entdecke Features im neuen Chartmetric Onboarding Center!"}]},{"type":"paragraph","children":[{"text":"Möchtest du deine Chartmetric-Expertise erweitern? Unser neues Onboarding Center ist jetzt verfügbar! Klicke einfach auf das Buch-Symbol in der oberen rechten Ecke neben deinem Profil, um auf übersichtliche Demonstrationen unserer Features zuzugreifen."}]},{"type":"paragraph","children":[{"text":"Das Onboarding Center bietet vereinfachte Ansichten, die dir dabei helfen, Chartmetric zu erkunden und zu meistern, ohne dich überfordert zu fühlen. Beginne noch heute deine Lernreise!"}]},{"type":"paragraph","children":[{"text":"Tipp: Du kannst jetzt auch deinen Namen und dein Profilbild in deinen Kontoeinstellungen aktualisieren!","italic":true}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/6deac96e-514e-4cc0-b228-19df2ab2b118.png","type":"image","children":[{"text":""}]}]},"es":{"title":"¡Descubre las Funciones en el Nuevo Centro de Incorporación de Chartmetric!","content":[{"type":"announcement-title","children":[{"text":"¡Descubre las funciones en el nuevo Centro de Incorporación de Chartmetric!"}]},{"type":"paragraph","children":[{"text":"¿Buscas mejorar tu experiencia con Chartmetric? ¡Nuestro nuevo Centro de Incorporación ya está disponible! Simplemente haz clic en el ícono del libro en la esquina superior derecha junto a tu perfil para acceder a demostraciones simplificadas de nuestras funciones."}]},{"type":"paragraph","children":[{"text":"El Centro de Incorporación ofrece vistas simplificadas diseñadas para ayudarte a explorar y dominar Chartmetric sin sentirte abrumado. ¡Comienza tu proceso de aprendizaje hoy!"}]},{"type":"paragraph","children":[{"text":"Consejo: ¡Ahora también puedes actualizar tu nombre y foto de perfil en la configuración de tu cuenta!","italic":true}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/6deac96e-514e-4cc0-b228-19df2ab2b118.png","type":"image","children":[{"text":""}]}]},"fr":{"title":"Découvrez les fonctionnalités dans le nouveau centre d''intégration Chartmetric !","content":[{"type":"announcement-title","children":[{"text":"Découvrez les fonctionnalités dans le nouveau Centre d''intégration Chartmetric !"}]},{"type":"paragraph","children":[{"text":"Vous cherchez à améliorer votre expertise Chartmetric ? Notre nouveau Centre d''intégration est maintenant disponible ! Cliquez simplement sur l''icône livre dans le coin supérieur droit à côté de votre profil pour accéder aux démonstrations simplifiées de nos fonctionnalités."}]},{"type":"paragraph","children":[{"text":"Le Centre d''intégration offre des vues simplifiées conçues pour vous aider à explorer et maîtriser Chartmetric sans vous sentir dépassé. Commencez votre parcours d''apprentissage dès aujourd''hui !"}]},{"type":"paragraph","children":[{"text":"Astuce : Vous pouvez également maintenant mettre à jour votre nom et photo de profil dans les paramètres de votre compte !","italic":true}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/6deac96e-514e-4cc0-b228-19df2ab2b118.png","type":"image","children":[{"text":""}]}]},"ja":{"title":"新しいChartmetric Onboarding Centerの機能を発見しよう！","content":[{"type":"announcement-title","children":[{"text":"新しいChartmetric Onboarding Centerの機能を発見しよう！"}]},{"type":"paragraph","children":[{"text":"Chartmetricの専門知識を向上させたいですか？新しいOnboarding Centerがご利用いただけるようになりました！プロフィールの隣、右上角の本のアイコンをクリックするだけで、機能の分かりやすいデモンストレーションにアクセスできます。"}]},{"type":"paragraph","children":[{"text":"Onboarding Centerでは、圧倒されることなくChartmetricを探索し、マスターできるように設計された簡潔なビューを提供しています。今すぐ学習の旅を始めましょう！"}]},{"type":"paragraph","children":[{"text":"ヒント：アカウント設定で名前とプロフィール画像も更新できるようになりました！","italic":true}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/6deac96e-514e-4cc0-b228-19df2ab2b118.png","type":"image","children":[{"text":""}]}]},"ko":{"title":"새로운 Chartmetric Onboarding Center에서 기능들을 발견해보세요!","content":[{"type":"announcement-title","children":[{"text":"새로운 Chartmetric Onboarding Center에서 기능들을 발견해보세요!"}]},{"type":"paragraph","children":[{"text":"Chartmetric 전문성을 향상시키고 싶으신가요? 새로운 Onboarding Center를 이용하실 수 있습니다! 프로필 옆 우측 상단의 책 아이콘을 클릭하시면 저희 기능들의 간편한 데모에 접근하실 수 있습니다."}]},{"type":"paragraph","children":[{"text":"Onboarding Center는 부담 없이 Chartmetric을 탐색하고 마스터할 수 있도록 도와주는 간소화된 뷰를 제공합니다. 오늘 학습 여정을 시작하세요!"}]},{"type":"paragraph","children":[{"text":"팁: 이제 계정 설정에서 이름과 프로필 사진도 업데이트하실 수 있습니다!","italic":true}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/6deac96e-514e-4cc0-b228-19df2ab2b118.png","type":"image","children":[{"text":""}]}]},"pt":{"title":"Descubra os Recursos no Novo Centro de Integração do Chartmetric!","content":[{"type":"announcement-title","children":[{"text":"Descubra Recursos no Novo Centro de Integração do Chartmetric!"}]},{"type":"paragraph","children":[{"text":"Quer aprimorar sua expertise no Chartmetric? Nosso novo Centro de Integração já está disponível! Simplesmente clique no ícone do livro no canto superior direito ao lado do seu perfil para acessar demonstrações simplificadas dos nossos recursos."}]},{"type":"paragraph","children":[{"text":"O Centro de Integração oferece visualizações simplificadas projetadas para ajudá-lo a explorar e dominar o Chartmetric sem se sentir sobrecarregado. Comece sua jornada de aprendizado hoje!"}]},{"type":"paragraph","children":[{"text":"Dica: Você também pode agora atualizar seu nome e foto de perfil nas configurações da sua conta!","italic":true}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/6deac96e-514e-4cc0-b228-19df2ab2b118.png","type":"image","children":[{"text":""}]}]}}'::jsonb WHERE id = 12;

UPDATE announcement_post SET translations = '{"de":{"title":"Chartmetric Teams: Teilen & Zusammenarbeiten","content":[{"type":"announcement-title","children":[{"text":"Chartmetric Teams: Teilen & Zusammenarbeiten"}]},{"type":"paragraph","children":[{"text":"Wir freuen uns zu verkünden, dass Premium-Nutzer jetzt dedizierte "},{"bold":true,"text":"Teams "},{"text":"erstellen können, um die Zusammenarbeit zu optimieren. "},{"bold":true,"text":"Teams "},{"text":"ermöglicht es Ihnen, Untergruppen von Nutzern zu organisieren und Chartmetric-Inhalte einfach mit genau den Personen zu teilen, die sie benötigen."}]},{"type":"paragraph","children":[{"bold":true,"text":"Erste Schritte"}]},{"type":"numbered-list","children":[{"type":"list-item","children":[{"text":"Klicken Sie auf „Erstellen Sie Ihr erstes Team\" oder das „+\"-Symbol im Profil-Dropdown in der oberen rechten Ecke Ihres Bildschirms"}]},{"type":"list-item","children":[{"text":"Benennen Sie Ihr Team und fügen Sie andere Premium-Nutzer hinzu"}]},{"type":"list-item","children":[{"text":"Verwalten Sie die Einstellungen jederzeit über das Dropdown-Menü—setzen Sie Symbole, benennen Sie Teams um oder passen Sie Mitgliederberechtigung an"}]},{"type":"list-item","children":[{"text":"Erstellen Sie mehrere Teams nach Ihren Bedürfnissen, indem Sie das „+\"-Symbol klicken"}]},{"type":"list-item","children":[{"text":"Teams machen das Teilen von Shortlists heute mühelos, mit Reports und zusätzlichem Content-Sharing in Kürze. Bereit, Ihren Workflow zu verbessern? Erstellen Sie jetzt Ihr erstes Team und erleben Sie ein neues Level kollaborativer Effizienz mit Chartmetric."}]}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/b7561378-c8bb-4952-a98d-5c0846b8d5da.png","type":"image","children":[{"text":""}]}]},"es":{"title":"Chartmetric Teams: Compartir y Colaborar","content":[{"type":"announcement-title","children":[{"text":"Chartmetric Teams: Compartir y Colaborar"}]},{"type":"paragraph","children":[{"text":"Nos complace anunciar que los usuarios premium ahora pueden crear "},{"bold":true,"text":"equipos "},{"text":"dedicados para optimizar la colaboración. "},{"bold":true,"text":"Teams "},{"text":"te permite organizar subgrupos de usuarios y compartir fácilmente contenido de Chartmetric con exactamente quién lo necesita."}]},{"type":"paragraph","children":[{"bold":true,"text":"Primeros Pasos"}]},{"type":"numbered-list","children":[{"type":"list-item","children":[{"text":"Haz clic en \"Crear tu primer equipo\" o en el ícono \"+\" desde el menú desplegable de tu perfil en la esquina superior derecha de tu pantalla"}]},{"type":"list-item","children":[{"text":"Nombra tu equipo y agrega otros usuarios premium"}]},{"type":"list-item","children":[{"text":"Administra la configuración en cualquier momento a través del menú desplegable—establecer íconos, renombrar equipos o ajustar permisos de miembros"}]},{"type":"list-item","children":[{"text":"Crea múltiples equipos para satisfacer tus necesidades haciendo clic en el ícono \"+\""}]},{"type":"list-item","children":[{"text":"Teams hace que compartir listas cortas sea fácil hoy, con informes y contenido adicional para compartir próximamente. ¿Listo para mejorar tu flujo de trabajo? Crea tu primer equipo ahora y experimenta un nuevo nivel de eficiencia colaborativa con Chartmetric."}]}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/b7561378-c8bb-4952-a98d-5c0846b8d5da.png","type":"image","children":[{"text":""}]}]},"fr":{"title":"Chartmetric Teams : Partager et collaborer","content":[{"type":"announcement-title","children":[{"text":"Chartmetric Teams : Partager et collaborer"}]},{"type":"paragraph","children":[{"text":"Nous sommes ravis d''annoncer que les utilisateurs premium peuvent désormais créer des "},{"bold":true,"text":"équipes "},{"text":"dédiées pour simplifier la collaboration. "},{"bold":true,"text":"Teams "},{"text":"vous permet d''organiser des sous-groupes d''utilisateurs et de partager facilement le contenu Chartmetric avec exactement ceux qui en ont besoin."}]},{"type":"paragraph","children":[{"bold":true,"text":"Pour commencer"}]},{"type":"numbered-list","children":[{"type":"list-item","children":[{"text":"Cliquez sur « Créer votre première équipe » ou sur l''icône « + » dans le menu déroulant de votre profil en haut à droite de votre écran"}]},{"type":"list-item","children":[{"text":"Nommez votre équipe et ajoutez d''autres utilisateurs premium"}]},{"type":"list-item","children":[{"text":"Gérez les paramètres à tout moment via le menu déroulant—définissez des icônes, renommez les équipes ou ajustez les permissions des membres"}]},{"type":"list-item","children":[{"text":"Créez plusieurs équipes selon vos besoins en cliquant sur l''icône « + »"}]},{"type":"list-item","children":[{"text":"Teams facilite le partage de listes restreintes dès aujourd''hui, avec des rapports et du partage de contenu supplémentaire à venir bientôt. Prêt à améliorer votre flux de travail ? Créez votre première équipe maintenant et découvrez un nouveau niveau d''efficacité collaborative avec Chartmetric."}]}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/b7561378-c8bb-4952-a98d-5c0846b8d5da.png","type":"image","children":[{"text":""}]}]},"ja":{"title":"Chartmetric Teams：共有・コラボレーション","content":[{"type":"announcement-title","children":[{"text":"Chartmetric Teams: 共有とコラボレーション"}]},{"type":"paragraph","children":[{"text":"プレミアムユーザーが専用の"},{"bold":true,"text":"チーム"},{"text":"を作成してコラボレーションを効率化できるようになったことをお知らせいたします。 "},{"bold":true,"text":"Teams"},{"text":"では、ユーザーのサブグループを整理し、必要な人とChartmetricコンテンツを簡単に共有できます。"}]},{"type":"paragraph","children":[{"bold":true,"text":"はじめに"}]},{"type":"numbered-list","children":[{"type":"list-item","children":[{"text":"画面右上のプロフィールドロップダウンから「初回チームを作成」または「+」アイコンをクリックしてください"}]},{"type":"list-item","children":[{"text":"チーム名を付けて、他のプレミアムユーザーを追加してください"}]},{"type":"list-item","children":[{"text":"ドロップダウンメニューからいつでも設定を管理できます—アイコンの設定、チーム名の変更、メンバー権限の調整が可能です"}]},{"type":"list-item","children":[{"text":"「+」アイコンをクリックしてニーズに応じた複数のチームを作成してください"}]},{"type":"list-item","children":[{"text":"Teamsは現在ショートリストの共有を簡単にし、レポートやその他のコンテンツ共有も近日公開予定です。ワークフローを向上させる準備はできていますか？今すぐ初回チームを作成して、Chartmetricで新しいレベルのコラボレーション効率を体験してください。"}]}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/b7561378-c8bb-4952-a98d-5c0846b8d5da.png","type":"image","children":[{"text":""}]}]},"ko":{"title":"Chartmetric Teams: 공유 및 협업","content":[{"type":"announcement-title","children":[{"text":"Chartmetric Teams: 공유 및 협업"}]},{"type":"paragraph","children":[{"text":"프리미엄 사용자가 이제 전용 "},{"bold":true,"text":"팀"},{"text":"을 생성하여 협업을 간소화할 수 있게 되었음을 알려드리게 되어 기쁩니다. "},{"bold":true,"text":"Teams"},{"text":"를 통해 사용자 하위 그룹을 구성하고 필요한 사람들과 정확히 Chartmetric 콘텐츠를 쉽게 공유할 수 있습니다."}]},{"type":"paragraph","children":[{"bold":true,"text":"시작하기"}]},{"type":"numbered-list","children":[{"type":"list-item","children":[{"text":"화면 우측 상단의 프로필 드롭다운에서 \"첫 번째 팀 만들기\" 또는 \"+\" 아이콘을 클릭하세요"}]},{"type":"list-item","children":[{"text":"팀 이름을 지정하고 다른 프리미엄 사용자를 추가하세요"}]},{"type":"list-item","children":[{"text":"드롭다운 메뉴를 통해 언제든지 설정을 관리하세요—아이콘 설정, 팀 이름 변경 또는 구성원 권한 조정"}]},{"type":"list-item","children":[{"text":"\"+\" 아이콘을 클릭하여 필요에 맞는 여러 팀을 생성하세요"}]},{"type":"list-item","children":[{"text":"Teams를 통해 오늘부터 손쉽게 단축목록을 공유할 수 있으며, 보고서 및 추가 콘텐츠 공유 기능도 곧 제공될 예정입니다. 워크플로를 향상시킬 준비가 되셨나요? 지금 첫 번째 팀을 만들고 Chartmetric과 함께 새로운 차원의 협업 효율성을 경험해보세요."}]}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/b7561378-c8bb-4952-a98d-5c0846b8d5da.png","type":"image","children":[{"text":""}]}]},"pt":{"title":"Chartmetric Teams: Compartilhe e Colabore","content":[{"type":"announcement-title","children":[{"text":"Chartmetric Teams: Compartilhe e Colabore"}]},{"type":"paragraph","children":[{"text":"Estamos empolgados em anunciar que usuários premium agora podem criar "},{"bold":true,"text":"equipes "},{"text":"dedicadas para otimizar a colaboração. "},{"bold":true,"text":"Teams "},{"text":"permite organizar subgrupos de usuários e compartilhar facilmente conteúdo do Chartmetric exatamente com quem precisa."}]},{"type":"paragraph","children":[{"bold":true,"text":"Primeiros Passos"}]},{"type":"numbered-list","children":[{"type":"list-item","children":[{"text":"Clique em \"Crie sua primeira equipe\" ou no ícone \"+\" no menu suspenso do seu perfil no canto superior direito da tela"}]},{"type":"list-item","children":[{"text":"Nomeie sua equipe e adicione outros usuários premium"}]},{"type":"list-item","children":[{"text":"Gerencie configurações a qualquer momento através do menu suspenso—defina ícones, renomeie equipes ou ajuste permissões de membros"}]},{"type":"list-item","children":[{"text":"Crie múltiplas equipes conforme suas necessidades clicando no ícone \"+\""}]},{"type":"list-item","children":[{"text":"Teams tornam o compartilhamento de listas selecionadas simples hoje, com relatórios e compartilhamento de conteúdo adicional em breve. Pronto para aprimorar seu fluxo de trabalho? Crie sua primeira equipe agora e experimente um novo nível de eficiência colaborativa com o Chartmetric."}]}]},{"alt":"image","url":"https://frill-prod.s3.us-west-2.amazonaws.com/2958395/b7561378-c8bb-4952-a98d-5c0846b8d5da.png","type":"image","children":[{"text":""}]}]}}'::jsonb WHERE id = 13;